-- Exercícios de Peitoral COMPLETOS baseados nos GIFs do Supabase Storage
-- Total: 93 exercícios

ON CONFLICT (id) DO UPDATE SET 
    name = EXCLUDED.name, 
    gif_path = EXCLUDED.gif_path, 
    equipment = EXCLUDED.equipment,
    difficulty = EXCLUDED.difficulty,
    updated_at = NOW();

-- Verificar total
SELECT COUNT(*) as total_peitoral FROM app_correcrat.exercises WHERE muscle_group_id = 'peitoral';
